function createBaseGetArtifactResponse(): GetArtifactResponse {
  return { eoscInline: undefined, hosted: undefined };
}

export const GetArtifactResponse: MessageFns<GetArtifactResponse> = {
  encode(message: GetArtifactResponse, writer: BinaryWriter = new BinaryWriter()): BinaryWriter {
    if (message.eoscInline !== undefined) {
      EoscInlineTool.encode(message.eoscInline, writer.uint32(10).fork()).join();
    }
    if (message.hosted !== undefined) {
      HostedTool.encode(message.hosted, writer.uint32(18).fork()).join();
    }
    return writer;
  },

  decode(input: BinaryReader | Uint8Array, length?: number): GetArtifactResponse {
    const reader = input instanceof BinaryReader ? input : new BinaryReader(input);
    const end = length === undefined ? reader.len : reader.pos + length;
    const message = createBaseGetArtifactResponse();
    while (reader.pos < end) {
      const tag = reader.uint32();
      switch (tag >>> 3) {
        case 1: {
          if (tag !== 10) {
            break;
          }

          message.eoscInline = EoscInlineTool.decode(reader, reader.uint32());
          continue;
        }
        case 2: {
          if (tag !== 18) {
            break;
          }

          message.hosted = HostedTool.decode(reader, reader.uint32());
          continue;
        }
      }
      if ((tag & 7) === 4 || tag === 0) {
        break;
      }
      reader.skip(tag & 7);
    }
    return message;
  },

  fromJSON(object: any): GetArtifactResponse {
    return {
      eoscInline: isSet(object.eoscInline)
        ? EoscInlineTool.fromJSON(object.eoscInline)
        : isSet(object.eosc_inline)
        ? EoscInlineTool.fromJSON(object.eosc_inline)
        : undefined,
      hosted: isSet(object.hosted) ? HostedTool.fromJSON(object.hosted) : undefined,
    };
  },

  toJSON(message: GetArtifactResponse): unknown {
    const obj: any = {};
    if (message.eoscInline !== undefined) {
      obj.eoscInline = EoscInlineTool.toJSON(message.eoscInline);
    }
    if (message.hosted !== undefined) {
      obj.hosted = HostedTool.toJSON(message.hosted);
    }
    return obj;
  },

  create<I extends Exact<DeepPartial<GetArtifactResponse>, I>>(base?: I): GetArtifactResponse {
    return GetArtifactResponse.fromPartial(base ?? ({} as any));
  },
  fromPartial<I extends Exact<DeepPartial<GetArtifactResponse>, I>>(object: I): GetArtifactResponse {
    const message = createBaseGetArtifactResponse();
    message.eoscInline = (object.eoscInline !== undefined && object.eoscInline !== null)
      ? EoscInlineTool.fromPartial(object.eoscInline)
      : undefined;
    message.hosted = (object.hosted !== undefined && object.hosted !== null)
      ? HostedTool.fromPartial(object.hosted)
      : undefined;
    return message;
  },
};

